// Customers__slider
var slider = tns({
    container: '.customers__slider',
    items: 2,
    slideBy: 1,
    center: true,
    startIndex: 1
});

// Add class for center item
function updateCenter(sliderInstance, container) {
    const info = sliderInstance.getInfo();
    const indexCurr = info.index;

    const elements = container.querySelectorAll(".slide-center");
    elements.forEach(el => el.classList.remove("slide-center"));

    info.slideItems[indexCurr].classList.add("slide-center");
}

const customersContainer = document.querySelector(".customers__slider");

updateCenter(slider, customersContainer);

slider.events.on("indexChanged", () => {
    updateCenter(slider, customersContainer);
});

// Slider Interface
var sliderInterface = tns({
    container: '.interface__slider',
    items: 5,
    slideBy: 1,
    center: true,
    startIndex: 2,
    gutter: 30,
    "mouseDrag": true,
    controls: false
});

// Add class for center item
const interfaceContainer = document.querySelector(".interface__slider");

updateCenter(sliderInterface, interfaceContainer);

sliderInterface.events.on("indexChanged", () => {
    updateCenter(sliderInterface, interfaceContainer);
});